mapper.select:
select

from big_data_reports
where  report_name = #{reportName,jdbcType=VARCHAR}
 and report_subject = #{reportSubject,jdbcType=INTEGER}
 and report_cycle = #{reportCycle,jdbcType=VARCHAR}
 and create_user = #{createUser,jdbcType=VARCHAR}

select
id, report_name as reportName, report_subject as reportSubject, report_cycle as reportCycle, report_state as isPublish,
create_user as createUser, create_time as createTime
from big_data_reports

  is_delete = 0

    and LOCATE(#{reportName,jdbcType=VARCHAR}, `report_name`)>0


    and  report_subject = #{reportSubject,jdbcType=INTEGER}


    and   report_cycle = #{reportCycle,jdbcType=VARCHAR}


    and  report_state = #{reportState,jdbcType=INTEGER}


order by create_time desc
